let map;
let geojsonLayer;

// Función para inicializar el mapa
function initMap() {
  // Coordenadas centrales aproximadas de Carabobo
  map = L.map('map').setView([10.15, -68.00], 9);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '© OpenStreetMap'
  }).addTo(map);
  renderGeoJSON();
}
function renderGeoJSON() {
  const dataFiltrada = appsmith.model.datosInfra || [];
  const geoJSONCarabobo = appsmith.model.municipiosGeoJSON; // Asegúrate de pasar esto en el Default Model

  if (!geoJSONCarabobo) return;

  // Si ya existe una capa (por un re-filtro), la quitamos
  if (geojsonLayer) {
    map.removeLayer(geojsonLayer);
  }
  geojsonLayer = L.geoJson(geoJSONCarabobo, {
    style: styleFeature,
    onEachFeature: (feature, layer) => {
      layer.on({
        mouseover: e => highlightFeature(e, dataFiltrada),
        mouseout: resetHighlight
      });
    }
  }).addTo(map);
}

// Color según si tiene datos o no (puedes hacerlo tipo mapa de calor)
function styleFeature(feature) {
  return {
    fillColor: '#3498db',
    weight: 2,
    opacity: 1,
    color: 'white',
    dashArray: '3',
    fillOpacity: 0.6
  };
}
function highlightFeature(e, dataFiltrada) {
  const layer = e.target;
  const nombreMun = layer.feature.properties.NOMBRE; // Ajusta según tu GeoJSON
  const codigoMun = layer.feature.properties.CODIGO; // Ajusta según tu GeoJSON (ej: 'VA')

  // Buscamos el match en los datos de la tabla SQL
  const info = dataFiltrada.find(d => d.alcaldia === codigoMun);
  const content = info ? `<b>${nombreMun}</b><br/>Registros: ${info.total_registros}<br/><small>${info.detalles_infraestructura}</small>` : `<b>${nombreMun}</b><br/>Sin registros`;
  document.getElementById('info-content').innerHTML = content;
  layer.setStyle({
    weight: 3,
    color: '#666',
    fillOpacity: 0.9
  });
}
function resetHighlight(e) {
  geojsonLayer.resetStyle(e.target);
  document.getElementById('info-content').innerHTML = 'Pasa el ratón sobre un municipio';
}

// Escuchamos cuando Appsmith está listo o los datos cambian
appsmith.onReady(() => {
  initMap();
});
appsmith.onModelUpdate(() => {
  if (map) {
    renderGeoJSON();
  }
});

